async function serveCached(res, { cache, key, ttl, maxEntries, force = false, label, build }: {
  cache: Map<string, {data:any; time:number}>; key: string; ttl: number; maxEntries: number;
  force?: boolean; label: string; build: () => Promise<any>;
}) {
  const cached = cache.get(key);
  if (!force && cached && Date.now() - cached.time < ttl) return res.json(cached.data);
  try {
    const data = await build();
    cacheSet(cache, key, data, ttl, maxEntries);
    res.json(data);
  } catch (err) {
    console.error(`Failed to fetch ${label}:`, err.message);
    if (cached) return res.json(cached.data);   // stale fallback — single statement of policy
    res.status(500).json({ error: `Failed to fetch ${label}` });
  }
}

Each endpoint becomes: auth guard + one serveCached call whose build() closure holds only the GitHub fetch + row mapping. The per-endpoint mapping code (commit/tag/branch/tree/file shaping) stays exactly where it is.

